/**
 * CustomCombobox – searchable dropdown replacing native <select>.
 *
 * Usage (auto-init): All .cbo-wrap elements in #app are wired automatically
 * whenever Router navigates to a new page.  Call CustomCombobox.initAll()
 * manually after dynamically inserting comboboxes.
 *
 * HTML structure (generated by UI.select() / selectInline()):
 *   <div class="cbo-wrap" id="..." data-name="fieldName">
 *     <input type="text" class="cbo-input form-control"  />
 *     <input type="hidden" class="cbo-value" name="fieldName" value="" />
 *     <div class="cbo-dropdown">
 *       <div class="cbo-option" data-value="val">Label</div>
 *       ...
 *     </div>
 *   </div>
 *
 * Reading the value: use $(el).find('[name="fieldName"]').val()
 * or r.find('.cbo-value').val() – same as a hidden input.
 *
 * Triggering change: the .cbo-wrap dispatches a native 'change' event
 * so existing $(document).on('change', '#app select', ...) listeners
 * still fire (they need updating to '.cbo-wrap' selector separately).
 */

window.CustomCombobox = (function () {

    function init(wrap) {
        if (wrap._cboInit) return;
        wrap._cboInit = true;

        const input    = wrap.querySelector('.cbo-input');
        const hidden   = wrap.querySelector('.cbo-value');
        const dropdown = wrap.querySelector('.cbo-dropdown');
        if (!input || !hidden || !dropdown) return;

        let highlighted = -1;
        let allOptions  = Array.from(dropdown.querySelectorAll('.cbo-option:not(.cbo-empty)'));

        function show() {
            dropdown.style.display = 'block';
            filter(input.value);
        }

        function hide() {
            dropdown.style.display = 'none';
            highlighted = -1;
        }

        function filter(query) {
            const q = (query || '').trim().toLowerCase();
            highlighted = -1;
            let visibleCount = 0;
            allOptions.forEach(opt => {
                const text = (opt.textContent || '').toLowerCase();
                const visible = !q || text.includes(q);
                opt.style.display = visible ? '' : 'none';
                if (visible) visibleCount++;
            });
            // show empty state if nothing matches
            let emptyEl = dropdown.querySelector('.cbo-empty');
            if (!emptyEl) {
                emptyEl = document.createElement('div');
                emptyEl.className = 'cbo-option cbo-empty';
                emptyEl.textContent = '—';
                dropdown.appendChild(emptyEl);
            }
            emptyEl.style.display = visibleCount === 0 ? '' : 'none';
        }

        function select(opt) {
            const val  = opt.getAttribute('data-value') ?? '';
            const text = opt.textContent.trim();
            input.value  = text;
            hidden.value = val;
            opt.classList.add('selected');
            allOptions.forEach(o => { if (o !== opt) o.classList.remove('selected'); });
            hide();
            // Use jQuery trigger so all .on('change') handlers fire correctly —
            // both direct bindings and delegated $(document).on('change', selector).
            if (window.jQuery) {
                $(hidden).trigger('change');   // fires for $('[name="x"]').on('change', fn)
                $(wrap).trigger('change');     // fires for $(document).on('change', '.cbo-wrap', fn)
            } else {
                hidden.dispatchEvent(new Event('change', { bubbles: true }));
                wrap.dispatchEvent(new Event('change', { bubbles: true }));
            }
        }

        function highlightMove(dir) {
            const visible = allOptions.filter(o => o.style.display !== 'none');
            if (!visible.length) return;
            highlighted = Math.min(Math.max(highlighted + dir, 0), visible.length - 1);
            visible.forEach((o, i) => o.classList.toggle('cbo-highlighted', i === highlighted));
            visible[highlighted]?.scrollIntoView({ block: 'nearest' });
        }

        // ── Events ──────────────────────────────────────────────────────

        input.addEventListener('focus', () => show());
        input.addEventListener('input', () => {
            show();
            // Clear hidden value while typing (forces re-selection)
            hidden.value = '';
        });

        input.addEventListener('keydown', e => {
            if (e.key === 'ArrowDown') { e.preventDefault(); show(); highlightMove(1); }
            else if (e.key === 'ArrowUp') { e.preventDefault(); highlightMove(-1); }
            else if (e.key === 'Enter') {
                e.preventDefault();
                const visible = allOptions.filter(o => o.style.display !== 'none');
                if (highlighted >= 0 && visible[highlighted]) {
                    select(visible[highlighted]);
                } else if (visible.length === 1) {
                    select(visible[0]);
                }
            } else if (e.key === 'Escape') {
                hide();
                // Restore display text from current hidden value
                const cur = allOptions.find(o => o.getAttribute('data-value') === hidden.value);
                input.value = cur ? cur.textContent.trim() : '';
            }
        });

        dropdown.addEventListener('mousedown', e => {
            const opt = e.target.closest('.cbo-option:not(.cbo-empty)');
            if (opt) { e.preventDefault(); select(opt); }
        });

        // Click outside
        document.addEventListener('mousedown', e => {
            if (!wrap.contains(e.target)) hide();
        }, true);

        // Mark current selection
        const curVal = hidden.value;
        if (curVal) {
            const cur = allOptions.find(o => o.getAttribute('data-value') === curVal);
            if (cur) cur.classList.add('selected');
        }

        // Initially hidden
        hide();
    }

    function initAll(root) {
        const container = root || document;
        container.querySelectorAll('.cbo-wrap').forEach(init);
    }

    return { init, initAll };
})();

// ── Auto-init on page renders (Router hook) ───────────────────────────────────
// MutationObserver watches #app for inserted .cbo-wrap elements
(function () {
    const observer = new MutationObserver(() => {
        CustomCombobox.initAll(document.getElementById('app'));
    });
    document.addEventListener('DOMContentLoaded', () => {
        const app = document.getElementById('app');
        if (app) {
            observer.observe(app, { childList: true, subtree: true });
        }
        CustomCombobox.initAll();
    });
})();
